using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class AuditLogConfiguration : IEntityTypeConfiguration<AuditLog>{public void Configure(EntityTypeBuilder<AuditLog> builder){builder.ToTable("audit_log");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("audit_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.EntityType).HasMaxLength(50).IsRequired();builder.Property(e => e.Action).HasMaxLength(40).IsRequired();builder.Property(e => e.OldValues).HasColumnType("jsonb");builder.Property(e => e.NewValues).HasColumnType("jsonb");builder.Property(e => e.IpAddress).HasColumnType("inet");builder.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId);builder.HasIndex(e => new { e.EntityType, e.EntityId, e.CreatedAt });builder.HasIndex(e => new { e.UserId, e.CreatedAt });}}
